import{_ as n,o as a,c as p,a2 as l}from"./chunks/framework.DvFsUg-r.js";const d=JSON.parse('{"title":"CAT-18. 교육 & 강의 설계","description":"","frontmatter":{"outline":[2,3]},"headers":[],"relativePath":"hermes/benchmark/education-training.md","filePath":"hermes/benchmark/education-training.md","lastUpdated":1781092690000}'),e={name:"hermes/benchmark/education-training.md"};function i(c,s,t,o,u,r){return a(),p("div",null,[...s[0]||(s[0]=[l(`<h1 id="cat-18-교육-강의-설계" tabindex="-1">CAT-18. 교육 &amp; 강의 설계 <a class="header-anchor" href="#cat-18-교육-강의-설계" aria-label="Permalink to &quot;CAT-18. 교육 &amp; 강의 설계&quot;">​</a></h1><blockquote><p><strong>평가 핵심</strong>: 에이전트가 교안, 워크숍, 이러닝, 평가 설계 등 <strong>교육 전문가 수준의 학습 콘텐츠</strong>를 만들 수 있는가?</p></blockquote><hr><h2 id="ed-01-워크숍-설계-풀데이" tabindex="-1">ED-01. 워크숍 설계 (풀데이) ⭐⭐⭐ <a class="header-anchor" href="#ed-01-워크숍-설계-풀데이" aria-label="Permalink to &quot;ED-01. 워크숍 설계 (풀데이) :star::star::star:&quot;">​</a></h2><h3 id="프롬프트" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>6시간짜리 &quot;데이터 기반 의사결정&quot; 워크숍을 설계해줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>대상: 중간관리자 (팀장급) 20명, 비기술 직군 (영업, 마케팅, HR, 재무)</span></span>
<span class="line"><span>목적: 데이터를 읽고 해석해서 팀 의사결정에 활용하는 역량 강화</span></span>
<span class="line"><span>장소: 사내 교육장 (테이블 5개 × 4명)</span></span>
<span class="line"><span>강사: 데이터분석팀 매니저</span></span>
<span class="line"><span></span></span>
<span class="line"><span>산출물: \`education/data-decision-workshop.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 워크숍 설계서</span></span>
<span class="line"><span>   - 학습 목표 3가지 (Bloom&#39;s Taxonomy 기반: 이해→적용→분석)</span></span>
<span class="line"><span>   - 시간표 (09:30~16:30, 점심 1시간)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   세션 1 (09:30~11:00): &quot;데이터 문해력 기초&quot;</span></span>
<span class="line"><span>   - 강의 30분: 평균, 중간값, 분포의 함정 (실제 사례)</span></span>
<span class="line"><span>   - 실습 30분: &quot;이 그래프가 거짓말하는 3가지&quot; (조작된 차트 읽기)</span></span>
<span class="line"><span>   - 토론 30분: 각 팀 업무에서 만나는 데이터 공유</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   세션 2 (11:15~12:30): &quot;대시보드 읽기 실전&quot;</span></span>
<span class="line"><span>   - 강의 20분: KPI 대시보드 해석법 (무엇을 봐야 하고 무엇은 무시해도 되는지)</span></span>
<span class="line"><span>   - 실습 55분: 가상 대시보드 3개를 보고 &quot;이 팀에 무슨 문제가 있나?&quot; 진단</span></span>
<span class="line"><span>     - 팀별 다른 대시보드 제공 → 발표 → 피드백</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   세션 3 (13:30~15:00): &quot;데이터로 설득하기&quot;</span></span>
<span class="line"><span>   - 강의 20분: 보고서에서 데이터 사용하는 법 (숫자 → 스토리)</span></span>
<span class="line"><span>   - 실습 70분: 케이스 스터디</span></span>
<span class="line"><span>     - 상황: &quot;마케팅 예산을 어디에 쓸까?&quot; 가상 데이터 제공</span></span>
<span class="line"><span>     - 팀별로 분석 → 결론 도출 → 3분 발표</span></span>
<span class="line"><span>     - 같은 데이터에서 다른 결론이 나오는 걸 체험</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   세션 4 (15:15~16:30): &quot;내 팀에 적용하기&quot;</span></span>
<span class="line"><span>   - 개인 작업 30분: &quot;다음 주 우리 팀 회의에서 데이터로 의사결정할 것 1가지&quot; 액션 플랜</span></span>
<span class="line"><span>   - 팀 코칭 30분: 강사가 돌아다니며 피드백</span></span>
<span class="line"><span>   - 마무리 15분: 회고 + 수료증</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 강사 가이드</span></span>
<span class="line"><span>   - 각 세션별 진행 스크립트 (발문, 전환 멘트, 시간 관리 팁)</span></span>
<span class="line"><span>   - 예상 질문 &amp; 답변 10개</span></span>
<span class="line"><span>   - 에너지 떨어질 때 대처법 (오후 졸음 방지 활동)</span></span>
<span class="line"><span>   - 토론이 안 될 때 / 한 사람이 독점할 때 대처법</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 참가자 워크북</span></span>
<span class="line"><span>   - 각 세션별 활동지 (빈칸 채우기, 차트 읽기 문제, 메모 공간)</span></span>
<span class="line"><span>   - 케이스 스터디 데이터셋 (표, 차트)</span></span>
<span class="line"><span>   - 액션 플랜 양식</span></span>
<span class="line"><span>   - 추천 도서/자료 목록</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 평가</span></span>
<span class="line"><span>   - 사전/사후 퀴즈 (10문항, 역량 변화 측정)</span></span>
<span class="line"><span>   - 만족도 설문 (15문항, 리커트 5점)</span></span>
<span class="line"><span>   - 3개월 후 팔로업 설문 (실제 업무 적용 여부)</span></span></code></pre></div><h3 id="평가-포인트" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] Bloom&#39;s Taxonomy 기반 학습 목표의 정확성</li><li>[ ] 강의(30%)↔실습(50%)↔토론(20%) 비율의 적절성</li><li>[ ] 케이스 스터디의 현실성과 난이도</li><li>[ ] 강사 가이드의 실전 팁 유용성</li><li>[ ] 워크북 활동지의 교육적 가치</li><li>[ ] 사전/사후 퀴즈의 측정 가능성</li><li>[ ] 6시간에 맞는 분량과 에너지 관리</li></ul><hr><h2 id="ed-02-이러닝-코스-설계" tabindex="-1">ED-02. 이러닝 코스 설계 ⭐⭐ <a class="header-anchor" href="#ed-02-이러닝-코스-설계" aria-label="Permalink to &quot;ED-02. 이러닝 코스 설계 :star::star:&quot;">​</a></h2><h3 id="프롬프트-1" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-1" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>온라인 이러닝 코스 &quot;신입사원을 위한 비즈니스 커뮤니케이션&quot;을 설계해줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>플랫폼: 사내 LMS (영상 + 퀴즈 + 과제)</span></span>
<span class="line"><span>대상: 신입사원 (입사 1개월 이내)</span></span>
<span class="line"><span>총 학습 시간: 약 4시간 (자기 주도형, 2주간 완료)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>산출물: \`education/elearning-biz-comm.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 코스 구조 (5개 모듈)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   Module 1: &quot;이메일 잘 쓰는 법&quot; (50분)</span></span>
<span class="line"><span>   - 영상 1-1: 나쁜 이메일 vs 좋은 이메일 비교 (10분)</span></span>
<span class="line"><span>   - 영상 1-2: 제목 쓰는 법, 수신/참조 구분, 본문 구조 (15분)</span></span>
<span class="line"><span>   - 영상 1-3: 상황별 이메일 템플릿 5가지 (10분)</span></span>
<span class="line"><span>   - 퀴즈: 이메일 교정 문제 5개 (10분)</span></span>
<span class="line"><span>   - 과제: &quot;이 상황에서 이메일 작성해보기&quot; → 동료 피어리뷰</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   Module 2: &quot;보고의 기술&quot; (50분)</span></span>
<span class="line"><span>   - 서면 보고 vs 구두 보고</span></span>
<span class="line"><span>   - &quot;1분 엘리베이터 브리핑&quot; 기법</span></span>
<span class="line"><span>   - 보고서 구조 (PREP: Point→Reason→Example→Point)</span></span>
<span class="line"><span>   - 퀴즈 + 과제 (가상 상황 보고서 작성)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   Module 3: &quot;회의 참여법&quot; (40분)</span></span>
<span class="line"><span>   - 회의 전 준비 (아젠다 읽기, 의견 정리)</span></span>
<span class="line"><span>   - 회의 중 발언법 (&quot;저는 ~라고 생각하는데, 왜냐하면...&quot;)</span></span>
<span class="line"><span>   - 회의록 작성법</span></span>
<span class="line"><span>   - 퀴즈 + 과제 (가상 회의 영상 보고 회의록 작성)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   Module 4: &quot;메신저 &amp; 채팅 에티켓&quot; (30분)</span></span>
<span class="line"><span>   - 슬랙/팀즈 에티켓 (태깅, 쓰레드, 이모지 리액션)</span></span>
<span class="line"><span>   - 긴급/비긴급 구분하여 연락</span></span>
<span class="line"><span>   - 카톡 업무 사용의 경계</span></span>
<span class="line"><span>   - 퀴즈</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   Module 5: &quot;어려운 대화&quot; (50분)</span></span>
<span class="line"><span>   - 거절하는 법 (&quot;죄송하지만&quot; 대신 대안 제시)</span></span>
<span class="line"><span>   - 피드백 받는 법 (방어적이지 않게)</span></span>
<span class="line"><span>   - 모르는 것 질문하는 법 (타이밍, 방식)</span></span>
<span class="line"><span>   - 시나리오 롤플레이 (선택지 기반)</span></span>
<span class="line"><span>   - 최종 평가 (종합 퀴즈 20문항)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 각 영상의 대본 구조 (Module 1-1 상세 작성)</span></span>
<span class="line"><span>   - 오프닝 후킹 (나쁜 이메일 사례로 시작)</span></span>
<span class="line"><span>   - 핵심 내용 (비교 형태)</span></span>
<span class="line"><span>   - 정리 &amp; 다음 영상 예고</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 퀴즈 &amp; 과제 설계</span></span>
<span class="line"><span>   - 각 모듈 퀴즈 (5~10문항씩)</span></span>
<span class="line"><span>   - 과제 루브릭 (어떤 기준으로 채점하는지)</span></span>
<span class="line"><span>   - 최종 평가 합격 기준 (80% 이상)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 학습 경로 &amp; 게이미피케이션</span></span>
<span class="line"><span>   - 모듈 순서 (필수 순서 vs 자유 선택)</span></span>
<span class="line"><span>   - 배지 시스템: &quot;이메일 마스터&quot;, &quot;보고 달인&quot; 등</span></span>
<span class="line"><span>   - 완료율 추적 대시보드 설계</span></span></code></pre></div><h3 id="평가-포인트-1" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-1" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 5개 모듈의 주제 선정 (신입사원 필수 역량)</li><li>[ ] 영상 + 퀴즈 + 과제 조합의 학습 효과</li><li>[ ] 대본의 교육적 구성 (후킹→본론→정리)</li><li>[ ] 퀴즈의 난이도 적절성</li><li>[ ] 과제 루브릭의 명확성</li><li>[ ] 게이미피케이션의 동기부여 효과</li><li>[ ] 4시간 총량의 적절한 분배</li></ul><hr><h2 id="ed-03-멘토링-프로그램-설계" tabindex="-1">ED-03. 멘토링 프로그램 설계 ⭐⭐ <a class="header-anchor" href="#ed-03-멘토링-프로그램-설계" aria-label="Permalink to &quot;ED-03. 멘토링 프로그램 설계 :star::star:&quot;">​</a></h2><h3 id="프롬프트-2" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-2" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>사내 멘토링 프로그램을 설계해줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>배경:</span></span>
<span class="line"><span>- 회사: IT 기업, 직원 200명</span></span>
<span class="line"><span>- 문제: 주니어(1~3년차) 이직률 25%, 성장 기회 부족이 퇴사 사유 1위</span></span>
<span class="line"><span>- 목표: 주니어 이직률 15%로 감소, 역량 성장 체감도 향상</span></span>
<span class="line"><span></span></span>
<span class="line"><span>산출물: \`education/mentoring-program.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 프로그램 개요</span></span>
<span class="line"><span>   - 프로그램명, 기간 (6개월), 대상</span></span>
<span class="line"><span>   - 멘토: 5년차 이상 시니어/매니저 (20명)</span></span>
<span class="line"><span>   - 멘티: 1~3년차 주니어 (30명)</span></span>
<span class="line"><span>   - 매칭: 1:1 또는 1:2 (직군 동일, 부서는 다르게)</span></span>
<span class="line"><span>   - 미팅: 격주 1시간 + 월 1회 그룹 세션</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 매칭 기준 &amp; 절차</span></span>
<span class="line"><span>   - 멘티 신청서 (목표, 기대사항, 선호 스타일)</span></span>
<span class="line"><span>   - 멘토 프로필 (전문 분야, 멘토링 스타일, 시간 가용성)</span></span>
<span class="line"><span>   - 매칭 알고리즘 (우선순위: 목표 분야 → 성격 유형 → 스케줄)</span></span>
<span class="line"><span>   - 미스매치 시 변경 절차</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 멘토 가이드</span></span>
<span class="line"><span>   - 멘토의 역할 &amp; 역할이 아닌 것 (코칭 vs 가르침 vs 관리)</span></span>
<span class="line"><span>   - 첫 미팅 가이드 (관계 구축, 기대 맞추기, 목표 설정)</span></span>
<span class="line"><span>   - 주제별 대화 가이드:</span></span>
<span class="line"><span>     - 커리어 방향: &quot;5년 후 어디에 있고 싶어요?&quot;</span></span>
<span class="line"><span>     - 기술 성장: &quot;요즘 어떤 걸 배우고 있어요?&quot;</span></span>
<span class="line"><span>     - 조직 적응: &quot;팀에서 어려운 점이 있나요?&quot;</span></span>
<span class="line"><span>     - 네트워킹: &quot;누구를 소개해주면 도움이 될까?&quot;</span></span>
<span class="line"><span>   - 경청 &amp; 질문 기법 (코칭 스킬)</span></span>
<span class="line"><span>   - 어려운 상황 대처 (멘티가 안 오는 경우, 관계가 어색한 경우)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 멘티 가이드</span></span>
<span class="line"><span>   - 멘토링에서 최대한 얻는 법</span></span>
<span class="line"><span>   - 미팅 준비 체크리스트 (매 미팅 전)</span></span>
<span class="line"><span>   - 개인 성장 계획(IDP) 작성 양식</span></span>
<span class="line"><span>   - 질문 준비 가이드 (&quot;좋은 질문이 좋은 멘토링을 만든다&quot;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 프로그램 운영</span></span>
<span class="line"><span>   - 킥오프 이벤트 (네트워킹 + 오리엔테이션)</span></span>
<span class="line"><span>   - 월간 그룹 세션 (주제별: 커리어, 기술, 리더십 등)</span></span>
<span class="line"><span>   - 중간 체크인 (3개월차, HR 진행)</span></span>
<span class="line"><span>   - 클로징 세레모니 (성장 공유 발표)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>6. 효과 측정</span></span>
<span class="line"><span>   - 멘티 역량 평가 (사전/사후)</span></span>
<span class="line"><span>   - 이직률 비교 (참가자 vs 비참가자)</span></span>
<span class="line"><span>   - 만족도 설문</span></span>
<span class="line"><span>   - 멘토링 관계 품질 지표 (미팅 횟수, NPS)</span></span></code></pre></div><h3 id="평가-포인트-2" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-2" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 매칭 기준의 현실적 세밀함</li><li>[ ] 멘토 가이드의 코칭 전문성</li><li>[ ] &quot;역할이 아닌 것&quot; 명시 (멘토≠매니저)</li><li>[ ] 어려운 상황 대처의 실용성</li><li>[ ] IDP 양식의 구조</li><li>[ ] 효과 측정의 과학적 접근 (비교군)</li><li>[ ] 6개월 프로그램의 지속 가능한 설계</li></ul><hr><h2 id="ed-04-사내-강사-양성-가이드" tabindex="-1">ED-04. 사내 강사 양성 가이드 ⭐⭐ <a class="header-anchor" href="#ed-04-사내-강사-양성-가이드" aria-label="Permalink to &quot;ED-04. 사내 강사 양성 가이드 :star::star:&quot;">​</a></h2><h3 id="프롬프트-3" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-3" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>현업 전문가를 사내 강사로 양성하는 프로그램을 설계해줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>배경:</span></span>
<span class="line"><span>- 외부 강사 비용이 부담, 현업 전문가의 지식 공유를 활성화하고 싶음</span></span>
<span class="line"><span>- 기술 좋은 시니어가 강의는 못 하는 경우가 많음</span></span>
<span class="line"><span></span></span>
<span class="line"><span>산출물: \`education/internal-trainer-program.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 사내 강사 양성 과정 (총 16시간, 4회)</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>   Day 1 (4h): &quot;성인 학습의 원리&quot;</span></span>
<span class="line"><span>   - 성인은 어떻게 배우는가 (안드라고지)</span></span>
<span class="line"><span>   - 학습 목표 설정법 (ABCD 기법)</span></span>
<span class="line"><span>   - 실습: 자기 전문 분야에서 학습 목표 3개 설정</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   Day 2 (4h): &quot;교안 설계&quot;</span></span>
<span class="line"><span>   - ADDIE 모델 간소화 (분석→설계→개발)</span></span>
<span class="line"><span>   - 60분 강의 구성법 (10-20-10 법칙)</span></span>
<span class="line"><span>   - 슬라이드 디자인 원칙 (글자 줄이기, 시각화)</span></span>
<span class="line"><span>   - 실습: 30분 강의 교안 작성</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   Day 3 (4h): &quot;전달 스킬&quot;</span></span>
<span class="line"><span>   - 발성, 시선, 제스처</span></span>
<span class="line"><span>   - 질문 활용법 (닫힌 질문 vs 열린 질문)</span></span>
<span class="line"><span>   - 실습 관리: 참여 유도, 시간 관리</span></span>
<span class="line"><span>   - 어려운 참가자 대처 (무관심, 지배적, 반대의견)</span></span>
<span class="line"><span>   - 실습: 5분 마이크로 티칭 + 피어 피드백</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   Day 4 (4h): &quot;마이크로 티칭 발표&quot;</span></span>
<span class="line"><span>   - 각자 15분 강의 시연</span></span>
<span class="line"><span>   - 동료 &amp; 전문 강사 피드백</span></span>
<span class="line"><span>   - 개선 포인트 정리</span></span>
<span class="line"><span>   - 사내 강사 인증서 수여</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 강사 도구 키트</span></span>
<span class="line"><span>   - 교안 템플릿 (PPT/마크다운)</span></span>
<span class="line"><span>   - 만족도 설문 템플릿</span></span>
<span class="line"><span>   - 아이스브레이커 활동 10가지</span></span>
<span class="line"><span>   - 에너지 활동(energizer) 5가지</span></span>
<span class="line"><span>   - 강의 체크리스트 (D-7, D-1, 당일)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 운영 가이드</span></span>
<span class="line"><span>   - 사내 강사 등록 &amp; 관리</span></span>
<span class="line"><span>   - 강의 일정 관리 (LMS 연동)</span></span>
<span class="line"><span>   - 인센티브 (강의 수당, 평가 반영)</span></span>
<span class="line"><span>   - 품질 관리 (만족도 3.5 미만 시 코칭)</span></span></code></pre></div><h3 id="평가-포인트-3" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-3" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 안드라고지(성인학습) 원리의 정확성</li><li>[ ] ADDIE/ABCD 등 교수설계 프레임워크 활용</li><li>[ ] 마이크로 티칭의 교육적 가치</li><li>[ ] 아이스브레이커/에너지 활동의 현실적 다양성</li><li>[ ] 16시간(4일)의 적절한 분배</li><li>[ ] 강사 도구 키트의 실용성</li><li>[ ] 인센티브와 품질 관리의 균형</li></ul><hr><h2 id="ed-05-역량-진단-개인-성장-계획" tabindex="-1">ED-05. 역량 진단 &amp; 개인 성장 계획 ⭐⭐ <a class="header-anchor" href="#ed-05-역량-진단-개인-성장-계획" aria-label="Permalink to &quot;ED-05. 역량 진단 &amp; 개인 성장 계획 :star::star:&quot;">​</a></h2><h3 id="프롬프트-4" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-4" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>직원 역량 진단 도구와 개인 성장 계획(IDP) 시스템을 설계해줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>대상: 전 직원 150명, 직군별 역량 모델 기반</span></span>
<span class="line"><span></span></span>
<span class="line"><span>산출물: \`education/competency-assessment-idp.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 역량 진단 도구</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   A. 공통 역량 (전 직원)</span></span>
<span class="line"><span>   - 커뮤니케이션, 문제해결, 협업, 자기주도학습, 디지털 리터러시</span></span>
<span class="line"><span>   - 각 역량: 5단계 레벨 (초급→중급→숙련→전문→마스터)</span></span>
<span class="line"><span>   - 각 레벨: 행동 지표 3개 (관찰 가능한 구체적 행동)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   B. 직군 역량 (개발팀 예시)</span></span>
<span class="line"><span>   - 코드 품질, 시스템 설계, 코드 리뷰, 기술 문서화, 트러블슈팅</span></span>
<span class="line"><span>   - 각 역량: 5단계 + 행동 지표</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   C. 리더 역량 (팀장급)</span></span>
<span class="line"><span>   - 목표 설정, 피드백, 위임, 갈등 관리, 인재 육성</span></span>
<span class="line"><span>   - 각 역량: 5단계 + 행동 지표</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   D. 진단 방법</span></span>
<span class="line"><span>   - 자기 진단 (본인)</span></span>
<span class="line"><span>   - 상사 진단 (직속 상사)</span></span>
<span class="line"><span>   - 선택적: 동료 진단 (2~3명)</span></span>
<span class="line"><span>   - 결과: 레이더 차트 (현재 레벨 vs 목표 레벨)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. IDP(개인 성장 계획) 양식 &amp; 가이드</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   양식:</span></span>
<span class="line"><span>   - 현재 역할 &amp; 목표 역할 (1~2년 후)</span></span>
<span class="line"><span>   - 역량 Gap 분석 (진단 결과 기반)</span></span>
<span class="line"><span>   - 성장 목표 3가지 (SMART 기준)</span></span>
<span class="line"><span>   - 각 목표별 학습 방법:</span></span>
<span class="line"><span>     - 70% 업무 경험 (어떤 프로젝트/태스크)</span></span>
<span class="line"><span>     - 20% 사회적 학습 (멘토, 동료, 커뮤니티)</span></span>
<span class="line"><span>     - 10% 공식 학습 (교육, 자격증, 독서)</span></span>
<span class="line"><span>   - 분기별 마일스톤</span></span>
<span class="line"><span>   - 리뷰 일정 (상사와 분기별 1:1)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   작성 가이드:</span></span>
<span class="line"><span>   - IDP 작성 예시 (3년차 개발자, 팀 리더 목표)</span></span>
<span class="line"><span>   - 흔한 실수: &quot;자격증만 나열&quot;, &quot;너무 많은 목표&quot;, &quot;업무와 무관한 계획&quot;</span></span>
<span class="line"><span>   - 상사의 역할: 지원자이지 심판관이 아님</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 추천 학습 리소스 매핑</span></span>
<span class="line"><span>   - 역량별 추천 학습 방법/리소스</span></span>
<span class="line"><span>   - 사내: 멘토링, 프로젝트 로테이션, 스터디</span></span>
<span class="line"><span>   - 외부: 인프런, 패캠, Coursera, 독서 목록</span></span>
<span class="line"><span>   - 예산: 자기개발비 100만원 활용 가이드</span></span></code></pre></div><h3 id="평가-포인트-4" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-4" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 역량별 5단계 행동 지표의 구체성</li><li>[ ] 진단 방법의 다면성 (자기+상사+동료)</li><li>[ ] 70-20-10 학습 모델의 정확한 적용</li><li>[ ] IDP 예시의 현실성</li><li>[ ] &quot;흔한 실수&quot;의 교육적 가치</li><li>[ ] 추천 리소스의 한국 시장 적합성</li><li>[ ] 전체 시스템의 지속 가능성</li></ul><hr><h2 id="ed-06-리더십-개발-프로그램" tabindex="-1">ED-06. 리더십 개발 프로그램 ⭐⭐⭐ <a class="header-anchor" href="#ed-06-리더십-개발-프로그램" aria-label="Permalink to &quot;ED-06. 리더십 개발 프로그램 :star::star::star:&quot;">​</a></h2><h3 id="프롬프트-5" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-5" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>신임 팀장 대상 리더십 개발 프로그램을 설계해줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>배경:</span></span>
<span class="line"><span>- 성과 좋은 시니어가 팀장이 되면 80%가 첫 6개월간 고전</span></span>
<span class="line"><span>- &quot;일 잘하는 사람&quot;과 &quot;사람을 이끄는 사람&quot;의 전환이 핵심</span></span>
<span class="line"><span></span></span>
<span class="line"><span>대상: 신임 팀장 12명 (팀장 임명 후 3개월 이내)</span></span>
<span class="line"><span>기간: 6개월 (월 1회 반일 워크숍 + 격주 피어 코칭)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>산출물: \`education/new-manager-leadership.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 프로그램 구조</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   Month 1: &quot;나는 이제 플레이어가 아니다&quot;</span></span>
<span class="line"><span>   - 리더 역할 전환의 심리적 과제</span></span>
<span class="line"><span>   - &quot;내가 하면 더 빠른데&quot; 함정 탈출</span></span>
<span class="line"><span>   - 위임의 기술 (RACI 매트릭스 실습)</span></span>
<span class="line"><span>   - 동료→상사 관계 전환 관리</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   Month 2: &quot;1:1 면담의 기술&quot;</span></span>
<span class="line"><span>   - 1:1 미팅 왜/어떻게</span></span>
<span class="line"><span>   - 코칭 대화 모델 (GROW)</span></span>
<span class="line"><span>   - 실습: 롤플레이 3세트 (칭찬, 피드백, 고민 상담)</span></span>
<span class="line"><span>   - 질문 레퍼토리 50개</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   Month 3: &quot;팀 목표 관리&quot;</span></span>
<span class="line"><span>   - OKR/KPI 설정과 캐스케이딩</span></span>
<span class="line"><span>   - 팀원별 동기부여 전략 (DISC 기반)</span></span>
<span class="line"><span>   - 성과가 안 나는 팀원 대화법</span></span>
<span class="line"><span>   - 실습: 가상 팀의 분기 OKR 설정</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   Month 4: &quot;갈등 관리 &amp; 어려운 대화&quot;</span></span>
<span class="line"><span>   - 갈등의 유형 (업무 갈등 vs 관계 갈등)</span></span>
<span class="line"><span>   - Thomas-Kilmann 모델</span></span>
<span class="line"><span>   - 실습: 갈등 시나리오 3개 롤플레이</span></span>
<span class="line"><span>     - &quot;두 팀원이 서로 험담&quot;</span></span>
<span class="line"><span>     - &quot;팀원이 내 결정에 공개적 반대&quot;</span></span>
<span class="line"><span>     - &quot;타 부서장과 자원 갈등&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   Month 5: &quot;채용 &amp; 인재 육성&quot;</span></span>
<span class="line"><span>   - 면접에서 진짜 역량 보는 법 (STAR 기법)</span></span>
<span class="line"><span>   - 신규 입사자 온보딩 책임</span></span>
<span class="line"><span>   - 팀원 성장 로드맵 만들기</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   Month 6: &quot;나만의 리더십 스타일&quot;</span></span>
<span class="line"><span>   - 6개월 회고: 어떤 리더가 되었나</span></span>
<span class="line"><span>   - 피어 피드백 (동기 팀장들끼리)</span></span>
<span class="line"><span>   - 개인 리더십 선언문 작성</span></span>
<span class="line"><span>   - 수료 &amp; 졸업 발표</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 피어 코칭 가이드</span></span>
<span class="line"><span>   - 3~4명 소그룹 (다른 부서 팀장끼리)</span></span>
<span class="line"><span>   - 격주 1시간 (화상 가능)</span></span>
<span class="line"><span>   - 진행 방식: 돌아가며 한 명이 고민 공유 → 나머지가 질문으로 코칭</span></span>
<span class="line"><span>   - 비밀유지 서약</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 참가자 워크북</span></span>
<span class="line"><span>   - 각 월별 사전 과제, 세션 중 활동지, 사후 액션 플랜</span></span>
<span class="line"><span>   - &quot;나의 리더십 일지&quot; (매주 짧은 회고 기록)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 효과 측정</span></span>
<span class="line"><span>   - 참가자 360도 피드백 (사전/사후)</span></span>
<span class="line"><span>   - 팀원 만족도 변화</span></span>
<span class="line"><span>   - 참가자 자기 효능감 설문</span></span></code></pre></div><h3 id="평가-포인트-5" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-5" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 6개월 커리큘럼의 논리적 흐름 (기본→심화)</li><li>[ ] &quot;내가 하면 더 빠른데&quot; 함정의 정확한 인식</li><li>[ ] GROW, RACI, DISC, STAR 등 프레임워크의 정확한 적용</li><li>[ ] 롤플레이 시나리오의 현실성</li><li>[ ] 피어 코칭의 구조화 수준</li><li>[ ] 리더십 선언문이라는 클로징의 교육적 의미</li><li>[ ] 360도 피드백의 사전/사후 비교 설계</li></ul><hr><h2 id="ed-07-기술-세미나-테크톡-운영-가이드" tabindex="-1">ED-07. 기술 세미나/테크톡 운영 가이드 ⭐ <a class="header-anchor" href="#ed-07-기술-세미나-테크톡-운영-가이드" aria-label="Permalink to &quot;ED-07. 기술 세미나/테크톡 운영 가이드 :star:&quot;">​</a></h2><h3 id="프롬프트-6" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-6" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>사내 테크톡(기술 세미나) 운영 가이드를 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>배경:</span></span>
<span class="line"><span>- 개발팀 40명, 매주 금요일 오후 1시간 테크톡 시작하려 함</span></span>
<span class="line"><span>- 현재: 기술 공유가 거의 없음, 팀별 사일로</span></span>
<span class="line"><span>- 목표: 지식 공유 문화 정착, 발표 역량 향상</span></span>
<span class="line"><span></span></span>
<span class="line"><span>산출물: \`education/techtalk-operations-guide.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 테크톡 운영 규칙</span></span>
<span class="line"><span>   - 주기: 격주 금요일 16:00~17:00</span></span>
<span class="line"><span>   - 형식: 발표 30분 + Q&amp;A 15분 + 자유 토론 15분</span></span>
<span class="line"><span>   - 발표자: 지원제 + 약한 의무 (분기 1회 이상 권장)</span></span>
<span class="line"><span>   - 청중: 개발팀 전원 (선택 참석이지만 참여 권장)</span></span>
<span class="line"><span>   - 녹화: 사내 Wiki에 아카이빙</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 발표 주제 가이드</span></span>
<span class="line"><span>   - 좋은 주제 예시 10개:</span></span>
<span class="line"><span>     - &quot;내가 이번 프로젝트에서 삽질한 것&quot;</span></span>
<span class="line"><span>     - &quot;새로 배운 기술 X를 실무에 적용한 경험&quot;</span></span>
<span class="line"><span>     - &quot;코드 리뷰에서 자주 보는 실수 패턴&quot;</span></span>
<span class="line"><span>     - &quot;성능 문제를 해결한 과정&quot;</span></span>
<span class="line"><span>     - ...</span></span>
<span class="line"><span>   - 피해야 할 주제:</span></span>
<span class="line"><span>     - 공식 문서 읽어주기</span></span>
<span class="line"><span>     - 너무 넓은 주제 (&quot;AI 전체 동향&quot;)</span></span>
<span class="line"><span>   - 주제 제출 양식 (제목, 요약 3줄, 청중 레벨)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 발표자 지원 키트</span></span>
<span class="line"><span>   - 슬라이드 템플릿 (회사 BI 적용)</span></span>
<span class="line"><span>   - 발표 구성 팁 (문제→삽질→해결→교훈)</span></span>
<span class="line"><span>   - 데모 환경 체크리스트</span></span>
<span class="line"><span>   - 긴장 완화 팁</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 운영 체크리스트</span></span>
<span class="line"><span>   - D-14: 발표자 확정, 주제 공지</span></span>
<span class="line"><span>   - D-3: 슬라이드 리뷰 (선택사항)</span></span>
<span class="line"><span>   - D-day: 장비 셋팅, 녹화 준비, 진행</span></span>
<span class="line"><span>   - D+1: 녹화 업로드, 발표 자료 공유</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 동기부여 시스템</span></span>
<span class="line"><span>   - 분기 Best Talk 투표 (상품: 도서 상품권)</span></span>
<span class="line"><span>   - 발표 횟수 뱃지 (1회, 5회, 10회)</span></span>
<span class="line"><span>   - 연말 &quot;올해의 테크톡&quot; 시상</span></span></code></pre></div><h3 id="평가-포인트-6" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-6" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 좋은 주제 예시의 실용성</li><li>[ ] &quot;삽질 공유&quot; 문화의 장려</li><li>[ ] 발표 구성 팁의 구체성</li><li>[ ] 운영 체크리스트의 실전성</li><li>[ ] 동기부여 시스템의 적절한 수위</li><li>[ ] 지원제의 참여 유도력</li><li>[ ] 전체적으로 &quot;지속 가능한&quot; 프로그램인지</li></ul><hr><h2 id="ed-08-평가-시험-문항-설계" tabindex="-1">ED-08. 평가 &amp; 시험 문항 설계 ⭐⭐ <a class="header-anchor" href="#ed-08-평가-시험-문항-설계" aria-label="Permalink to &quot;ED-08. 평가 &amp; 시험 문항 설계 :star::star:&quot;">​</a></h2><h3 id="프롬프트-7" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-7" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>교육 후 역량을 평가하는 시험 문항을 설계해줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>교육: &quot;개인정보보호법 실무&quot; (전 직원 대상 법정 교육)</span></span>
<span class="line"><span>평가 목적: 교육 이수 확인 + 실무 적용 가능성 검증</span></span>
<span class="line"><span>합격 기준: 70% 이상</span></span>
<span class="line"><span></span></span>
<span class="line"><span>산출물: \`education/privacy-exam-design.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 시험 설계 명세</span></span>
<span class="line"><span>   - 총 문항: 30문항 (60분)</span></span>
<span class="line"><span>   - 문항 유형 배분:</span></span>
<span class="line"><span>     - 객관식 4지선다 (15문항, 각 2점)</span></span>
<span class="line"><span>     - O/X (5문항, 각 2점)</span></span>
<span class="line"><span>     - 사례형 (5문항, 각 4점): 실제 상황 제시 → 올바른 대응 선택</span></span>
<span class="line"><span>     - 서술형 (5문항, 각 4점): 자유 작성</span></span>
<span class="line"><span>   - 난이도 배분: 쉬움 30% / 보통 50% / 어려움 20%</span></span>
<span class="line"><span>   - 출제 범위: 수집, 이용, 제공, 파기, 유출 대응, 정보주체 권리</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 문항 전체 (30문항)</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>   각 문항:</span></span>
<span class="line"><span>   - 문항 번호, 유형, 난이도</span></span>
<span class="line"><span>   - 출제 의도 (어떤 역량을 측정하는가)</span></span>
<span class="line"><span>   - 문항 (실제 시험에 나올 형태 그대로)</span></span>
<span class="line"><span>   - 정답 &amp; 해설</span></span>
<span class="line"><span>   - 오답 선지별 오답 이유 (객관식)</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>   사례형 문항 예시:</span></span>
<span class="line"><span>   &quot;마케팅팀에서 이벤트 참여 고객 명단(이름, 전화번호)을 </span></span>
<span class="line"><span>   외부 경품 배송업체에 전달하려 합니다. 아래 중 올바른 절차는?&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   서술형 문항 예시:</span></span>
<span class="line"><span>   &quot;회사 USB에 고객 개인정보가 담긴 파일이 저장된 상태로 </span></span>
<span class="line"><span>   USB를 분실했습니다. 개인정보보호법에 따라 취해야 할 조치를 </span></span>
<span class="line"><span>   시간 순서대로 서술하시오.&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 채점 기준 (서술형)</span></span>
<span class="line"><span>   - 각 서술형 문항: 모범 답안 + 부분 점수 기준</span></span>
<span class="line"><span>   - 핵심 키워드 포함 여부로 채점</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 시험 운영 가이드</span></span>
<span class="line"><span>   - 온라인 시행 시 부정행위 방지 (문항 순서 랜덤, 시간 제한)</span></span>
<span class="line"><span>   - 재시험 정책 (1회 추가 기회, 문항 교체)</span></span>
<span class="line"><span>   - 결과 분석: 문항별 정답률로 교육 개선 포인트 도출</span></span></code></pre></div><h3 id="평가-포인트-7" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-7" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 개인정보보호법 내용의 정확성</li><li>[ ] 문항 유형의 적절한 배분 (기억→이해→적용)</li><li>[ ] 사례형 문항의 현실적 시나리오</li><li>[ ] 서술형 채점 기준의 공정성</li><li>[ ] 오답 선지의 교육적 가치 (그럴듯하지만 틀린 이유)</li><li>[ ] 30문항의 출제 범위 균형</li><li>[ ] 부정행위 방지 대책의 현실성</li></ul>`,50)])])}const q=n(e,[["render",i]]);export{d as __pageData,q as default};
